rt_order": 3}, {"name": "DESIRABLE", "slug": "desirable", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Mississippi early 1900s (likely Success x Jewett), released 1945", "traits": "Very large nuts (39-48/lb), soft medium shell, easy to crack", "flesh_fruit": "", "yield_notes": "Consistent heavy production, reliable annual bearer", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "WICHITA", "slug": "wichita", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USDA Brownwood TX 1940 (Halbert x Mahan), released 1959", "traits": "Large nuts (50-62/lb), moderately upright, vigorous, purplish-black stripes on shell", "flesh_fruit": "", "yield_notes": "Very prolific, precocious (bears early 5-6 years), tendency to overbear", "growing_notes": "Suitable for cooler subtropics/warm temperate Brisbane area. Type A pollinator - excellent for Western Schley. Light producer early, heavy after year 12. Thick shell. Prefers dry climate but adapts with management.", "availability": "Daley''s Fruit Trees QLD, Australian pecan nurseries", "sort_order": 5}, {"name": "WESTERN SCHLEY", "slug": "western-schley", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "San Saba TX seedling discovery 1895, developed by E.E. Risien", "traits": "Small oblong nuts (72-77/lb), thin smooth shell, productive", "flesh_fruit": "", "yield_notes": "Very productive in dry climates, self-pollinator, consistent bearer", "growing_notes": "", "availability": "", "sort_order": 6}, {"name": "BURKETT", "slug": "burkett", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Callahan County TX native seedling, introduced 1911", "traits": "Large round nuts (uniformly round shape), thin shell, natural symmetry", "flesh_fruit": "", "yield_notes": "Moderate, late ripening variety", "growing_notes": "", "availability": "", "sort_order": 7}, {"name": "CADDO", "slug": "caddo", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USDA Georgia 1922-23 (Brooks x Alley), released 1968", "traits": "Medium-small elongated nuts (67-70/lb), football shaped, slender", "flesh_fruit": "", "yield_notes": "One of best yielders - highly productive, consistent annual bearer, precocious", "growing_notes": "Excellent for Brisbane subtropical climate. Strong limbs, disease resistant foliage (dark green). Early-mid ripening (October 11). Moderate scab resistance - manageable with standard spray. Bears 5-6 years. Type I pollinator. Watch for black aphids. Outstanding reliable producer.", "availability": "Australian pecan nurseries, recommended variety", "sort_order": 8}, {"name": "ELLIOTT", "slug": "elliott", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Florida seedling 1912, discovered by Henry Elliot", "traits": "Small teardrop-shaped nuts (62+/lb), smooth symmetrical, distinctive shape", "flesh_fruit": "", "yield_notes": "Consistent producer, alternate bearing pattern, quality maintained in heavy years", "growing_notes": "SPECIALTY PECAN - premium pricing. EXCELLENT scab resistance - ideal for Brisbane humid climate. Drought tolerant, disease resistant. Type II pollinator. Pairs with Pawnee, Caddo, Kanza. Sought after by candy makers, chefs. High oil content exceptional flavor. Slow to produce initially but very reliable. Perfect for subtropical Florida/Brisbane conditions.", "availability": "Australian nurseries, highly recommended for Brisbane", "sort_order": 9}, {"name": "KANZA", "slug": "kanza", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USDA 1996 (Major x Shoshoni), named after Kanza Nation of Kansas", "traits": "Small round nuts (65-74/lb), attractive, similar appearance to Elliott", "flesh_fruit": "", "yield_notes": "Good mature production, some alternate bearing", "growing_notes": "", "availability": "", "sort_order": 10}, {"name": "CHEYENNE", "slug": "cheyenne", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USDA 1970 (Clark x Odom), named after Cheyenne Nation", "traits": "Medium nuts (55-60/lb), distinctive wrinkled kernel appearance, small tree with lateral branching", "flesh_fruit": "", "yield_notes": "Highly productive, precocious (5-7 years), severe alternate bearing tendency", "growing_notes": "", "availability": "", "sort_order": 11}, {"name": "MAHAN", "slug": "mahan", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "1927 variety, named after J.C. Mahan", "traits": "VERY LARGE nuts (40-50/lb), soft shell, vigorous tree", "flesh_fruit": "", "yield_notes": "Heavy early bearer, production declines with age", "growing_notes": "HEIRLOOM variety (100 years). Eye appeal from large size but kernel filling issues. Prefers arid warm winter climates. Mid-late November ripening. Used extensively in breeding programs (parent of many varieties). Type A pollinator. NOT recommended for new plantings - superseded by better varieties. Historical significance only.", "availability": "Rare, specialty nurseries only", "sort_order": 12}, {"name": "CAPE FEAR", "slug": "cape-fear", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "North Carolina 1937 (Schley seedling)", "traits": "Medium nuts (55-60/lb), thin shell, resembles Stuart in size/shape", "flesh_fruit": "", "yield_notes": "Very precocious, early strong bearer, can overload", "growing_notes": "", "availability": "", "sort_order": 13}, {"name": "SUMNER", "slug": "sumner", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USDA breeding program", "traits": "Medium nuts, elongated shape, thin shell, attractive visual appeal", "flesh_fruit": "", "yield_notes": "Good producer, consistent", "growing_notes": "GOOD scab resistance - recommended for Brisbane humid climate. Disease resistant, easy-to-peel nuts. Great shade tree. Type II pollinator. Pairs with Cape Fear, Creek. Late-season pollinizer. Water needs when young. Well-suited subtropical/commercial use.", "availability": "Australian nurseries", "sort_order": 14}, {"name": "CHOCTAW", "slug": "choctaw", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USDA 1950s-70s release, named after Choctaw Nation", "traits": "Large nuts, thin hull, resembles Western Schley appearance", "flesh_fruit": "", "yield_notes": "Moderate, requires perfect management", "growing_notes": "", "availability": "", "sort_order": 15}, {"name": "KIOWA", "slug": "kiowa", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USDA 1976 (Mahan x Odom parentage, likely Mahan x Desirable)", "traits": "VERY LARGE nuts (45/lb), high-percentage kernel", "flesh_fruit": "", "yield_notes": "High yield potential, alternate bearing tendency", "growing_notes": "Late season maturity (late October-early November). Commonly recommended for Southeast U.S. Great scab resistance. Type A pollinator. Large size impressive but requires long growing season - suitable for Brisbane if season length adequate. Commercial favorite for size/quality combination.", "availability": "Australian nurseries, commercial variety", "sort_order": 16}, {"name": "OCONEE", "slug": "oconee", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "University of Georgia 1989 release", "traits": "Large nuts, cold-resistant, low-maintenance hybrid", "flesh_fruit": "", "yield_notes": "Good, consistent", "growing_notes": "", "availability": "", "sort_order": 17}, {"name": "SIOUX", "slug": "sioux", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "USDA (Schley x Carmichael cross)", "traits": "Small nuts, thin shell, very light color, gorgeous tree form", "flesh_fruit": "", "yield_notes": "Good", "growing_notes": "ONE OF BEST EATING QUALITY - top flavor pecan. Small size excellent for mixed nut applications. Requires fungicide in HIGH HUMIDITY areas - Brisbane would need sprays. Little training required - recommended best homeowner tree. Type A pollinator. Fresh flavor best in world. Native pecan flavor quality without hard shell.", "availability": "Specialty nurseries", "sort_order": 18}, {"name": "NATIVE/WILD PECANS", "slug": "native-wild-pecans", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Indigenous North America - discovered 16th century by European explorers, staple food for Native Americans since ancient times", "traits": "Variable size/shape (70-150/lb typical), thick hard shells, natural genetic diversity tree to tree", "flesh_fruit": "", "yield_notes": "Variable, no irrigation typically, rely on natural rainfall", "growing_notes": "INDIGENOUS HEIRLOOM - oldest pecan type. Algonquin word ''pacane'' = ''nut so hard requires stone to crack''. EXCELLENT disease resistance due to genetic variability. Heat-tolerant (especially Texas natives). Sustainable - no irrigation/fertilizer/spraying. Best for pecan pieces in candies/pralines/pies. Shell thickness natural protection from animals. Flavor superior to clones - stress improves taste. NOT suitable Brisbane (requires sourcing from wild North American trees).", "availability": "NOT available Australia - U.S. wild harvest only (Texas, Missouri)", "sort_order": 19}], "variety_count": 20}'::jsonb,
