UPDATE public.garden_import_queue SET payload = '{"species": "Persimmon", "species_slug": "persimmon", "varieties": [{"name": "Fuyu", "slug": "fuyu", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Japan, selected in late 1800s", "traits": "Round, squat, tomato-shaped fruit, 5-7cm diameter; bright orange-red skin and flesh; medium-sized tree to 15ft", "flesh_fruit": "Crisp, sweet, firm texture even when ripe; seedless; can be eaten like an apple or allowed to soften", "yield_notes": "Heavy, consistent producer; begins fruiting 2-3 years", "growing_notes": "", "availability": "", "sort_order": 0}, {"name": "Jiro (Ichikikei Jiro)", "slug": "jiro-ichikikei-jiro", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Japan, traditional cultivar, 1800s", "traits": "Large, square-shaped fruit; flat with four distinct lobes; glossy orange skin; compact tree to 12-15ft", "flesh_fruit": "Firm, crisp, sweet with mild flavor; thin, tender skin; seedless; larger than Fuyu", "yield_notes": "Excellent yields when mature; can be erratic when young; very productive", "growing_notes": "EXCELLENT FOR BRISBANE - Grown commercially in Queensland. Thrives in subtropical climates. More cold-hardy than Fuyu. Heat and humidity resistant. Self-pollinating. Ripens late October-November. Fruits early March in subtropics. Popular with Brisbane orchardists.", "availability": "Perrys Fruit Nursery, Daley''s Fruit, Rossmount Orchard, Stark Bros", "sort_order": 1}, {"name": "Izu", "slug": "izu", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Japan, early variety", "traits": "Small to medium-sized fruit, tomato-shaped; bright orange; semi-dwarf tree, compact growth", "flesh_fruit": "Sweet, crisp when firm; pale orange flesh; seedless; excellent quality", "yield_notes": "Good cropping; productive for smaller tree size", "growing_notes": "VERY GOOD FOR BRISBANE - Early ripening (September-October). More cold-hardy than Fuyu but adapts well to Brisbane''s mild winters. Suitable for smaller Brisbane backyards. Heat tolerant. Ideal for subtropical Queensland.", "availability": "Daley''s Fruit, Garden Express, Nurseries Online Australia", "sort_order": 2}, {"name": "Dai Dai Maru", "slug": "dai-dai-maru", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Japan, traditional variety", "traits": "Medium to large, distinctive square shape similar to Fuyu; attractive tree with weeping form", "flesh_fruit": "Sweet, good quality; firm texture; non-astringent", "yield_notes": "Good producer; reliable cropping", "growing_notes": "GOOD FOR BRISBANE - Popular in Australian home gardens. Ornamental value with weeping form. Most often seen in Queensland markets. Adapts to subtropical conditions. Heat tolerant.", "availability": "Nurseries Online Australia, Daley''s Fruit", "sort_order": 3}, {"name": "Jiro Dwarf", "slug": "jiro-dwarf", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Japan, dwarf sport of Jiro", "traits": "Compact tree reaching only 2m height; large, flat fruit; perfect for containers and small spaces", "flesh_fruit": "Excellent fruit quality; sweet, crisp; seedless", "yield_notes": "Good yields despite smaller tree size", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Fuyu Dwarf", "slug": "fuyu-dwarf", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Japan, compact sport of Fuyu", "traits": "Semi-dwarf tree to 2m with pruning; same fruit as standard Fuyu; manageable size", "flesh_fruit": "Identical to Fuyu - sweet, crisp, seedless; large, flat, orange-red fruit", "yield_notes": "Excellent yields; heavy bearer despite smaller tree", "growing_notes": "PERFECT FOR BRISBANE BACKYARDS - Best for growing in pots or small Brisbane yards. Widely available in Australian nurseries. Heat tolerant. Low maintenance. Self-pollinating. Ripens October-November.", "availability": "Daley''s Fruit, Garden Express, Nurseries Online Australia", "sort_order": 5}, {"name": "Suruga", "slug": "suruga", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Japan", "traits": "Medium to large fruit; reddish-orange skin; attractive appearance", "flesh_fruit": "Very sweet - one of the sweetest non-astringent types; spicy-sweet flavor", "yield_notes": "Good production; reliable bearer", "growing_notes": "", "availability": "", "sort_order": 6}, {"name": "Gosho (Giant Fuyu)", "slug": "gosho-giant-fuyu", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Japan; name means ''Imperial Palace''", "traits": "Very large, heavy fruit - bigger version of Fuyu; similar square shape", "flesh_fruit": "Tannin-free; sweet with date/apricot flavor; excellent quality", "yield_notes": "Good yields of extra-large fruit", "growing_notes": "SUITABLE FOR BRISBANE - Adapts to subtropical conditions. Heat tolerant. Impressive fruit size for show and markets.", "availability": "Specialty fruit tree nurseries", "sort_order": 7}, {"name": "Maekawa Jiro", "slug": "maekawa-jiro", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Japan, bud sport of Jiro", "traits": "Large to extra-large fruit; compact tree under 15ft; prone to tip cracking in extreme heat", "flesh_fruit": "Sugar cane-like sweetness; lacks spicy notes; excellent quality", "yield_notes": "Good yields; tree not very vigorous but productive", "growing_notes": "SUITABLE FOR BRISBANE - Adapts to subtropical climate. Can crack in extreme heat - harvest promptly when ripe. Ripens late October-November.", "availability": "Specialty nurseries", "sort_order": 8}, {"name": "Imoto", "slug": "imoto", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Japan", "traits": "Squat Fuyu/Jiro shape; reddish-brown skin when ripe rather than orange", "flesh_fruit": "Extremely sweet; firm flesh; no astringency", "yield_notes": "Good producer", "growing_notes": "", "availability": "", "sort_order": 9}, {"name": "Matsumoto-Wase Fuyu", "slug": "matsumoto-wase-fuyu", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Japan, ''Wase'' means early", "traits": "Vigorous tree 16-18ft; larger than original Fuyu", "flesh_fruit": "Nearly identical flavor to Fuyu - difficult to distinguish; sweet and crisp", "yield_notes": "Consistent heavy bearer", "growing_notes": "EXCELLENT FOR BRISBANE - Ripens late September-October. Earlier than standard Fuyu. Heat and humidity tolerant. Vigorous grower suited to subtropical Queensland.", "availability": "Specialty fruit nurseries", "sort_order": 10}, {"name": "Hanafuyu", "slug": "hanafuyu", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Japan, ''Hana'' means flower", "traits": "Dwarf tree, only 10ft at maturity; oblong fruit shape; very large fruit", "flesh_fruit": "Sweet whether hard or soft; versatile eating stages", "yield_notes": "Biennial bearing tendency - heavy crop one year, lighter the next", "growing_notes": "GOOD FOR BRISBANE - Dwarf size perfect for small Brisbane yards. Biennial bearing pattern. Heat tolerant.", "availability": "Specialty nurseries", "sort_order": 11}, {"name": "Nightingale", "slug": "nightingale", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Japan, traditional variety", "traits": "Large fruit tending to red color; early ripening; small tree suitable for netting", "flesh_fruit": "Very sweet when fully ripe and soft; jelly-like consistency; excellent quality", "yield_notes": "Prolific yields - excellent producer; lots of large fruit", "growing_notes": "EXCELLENT FOR BRISBANE - Recommended by Australian nurseries. Early ripening suits Brisbane climate. Grows well in subtropical Queensland. Popular in home gardens. Birds love it - use netting. Heat tolerant.", "availability": "Nurseries Online Australia, Daley''s Fruit", "sort_order": 12}, {"name": "Hachiya", "slug": "hachiya", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Japan, widely cultivated since 1800s", "traits": "Large, acorn-shaped fruit; bright orange skin; vigorous, upright tree", "flesh_fruit": "Intensely sweet when ripe - honeyed with tropical fruit notes; jelly-like, custardy; seedless", "yield_notes": "Very productive; heavy bearer; consistent crops", "growing_notes": "", "availability": "", "sort_order": 13}, {"name": "Flat Seedless", "slug": "flat-seedless", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Traditional Australian variety", "traits": "Large, flat fruit; vigorous tree; pale fruit color", "flesh_fruit": "Seedless; pale flesh; sweet when fully soft", "yield_notes": "Good cropping", "growing_notes": "", "availability": "", "sort_order": 14}, {"name": "Hyakume (Chocolate/Cinnamon Persimmon)", "slug": "hyakume-chocolate-cinnamon-persimmon", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Japan, traditional cultivar", "traits": "Large, round fruit; bright orange skin; brown-flecked flesh when pollinated", "flesh_fruit": "Light cinnamon color; brown sugar taste; spicy-sweet; seeded varieties are sweetest", "yield_notes": "Good yields", "growing_notes": "", "availability": "", "sort_order": 15}, {"name": "Maru (Chocolate Persimmon, Tsurunoko)", "slug": "maru-chocolate-persimmon-tsurunoko", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Japan, revered heirloom variety", "traits": "Small to medium oblong fruit; bright orange skin; dark brown interior", "flesh_fruit": "Deep brown jelly-like flesh; very sweet but not overly sweet; hints of nutmeg; decadent texture", "yield_notes": "Moderate yields", "growing_notes": "SUITABLE FOR BRISBANE - Revered heirloom grown by artisanal orchardists. Unique chocolate appearance (not flavor). Connoisseur''s choice. Heat tolerant.", "availability": "Specialty nurseries, farmers markets (rare)", "sort_order": 16}, {"name": "Saijo", "slug": "saijo", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Japan, name means ''the very best one''", "traits": "Small to medium oblong, conical fruit; 1.5-2in long; bright orange; beautiful tree", "flesh_fruit": "Extremely sweet - honey-like; hints of mango/papaya; seedless; translucent when ripe", "yield_notes": "Productive; begins bearing 2-3 years", "growing_notes": "", "availability": "", "sort_order": 17}, {"name": "Tanenashi", "slug": "tanenashi", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Japan, name translates to ''seedless''", "traits": "Medium-large conical fruit; light orange to red-orange skin; vigorous, upright tree to 30ft", "flesh_fruit": "Yellow-orange flesh; dry texture when ripe; sweet, rich flavor; completely seedless", "yield_notes": "Heavy, prolific producer; stores extremely well on tree", "growing_notes": "", "availability": "", "sort_order": 18}, {"name": "Tamopan", "slug": "tamopan", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "China, traditional variety", "traits": "Very large, flat fruit with distinctive ring constriction around middle; tomato with a hat shape; large tree to 30ft", "flesh_fruit": "Sweet when fully soft; orange flesh; unique appearance", "yield_notes": "Moderately productive", "growing_notes": "", "availability": "", "sort_order": 19}, {"name": "Eureka", "slug": "eureka", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Selection developed in USA", "traits": "Medium-sized, flat-shaped fruit; red skin; small, relatively compact tree", "flesh_fruit": "Extremely high quality; typically contains seeds; excellent texture that stores well", "yield_notes": "Heavy producing; self-fruitful; proven best commercial variety in some regions", "growing_notes": "EXCELLENT FOR BRISBANE - Popular across US and Asia. Heat zones 8-11. Exceptional fruit quality. Ripens late October-early November. Stores well.", "availability": "Stark Bros, Australian specialty nurseries", "sort_order": 20}, {"name": "Great Wall", "slug": "great-wall", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "China, discovered near Great Wall by J. Russel Smith in 1920s", "traits": "Medium orange fruit; erect growing tree, taller than Fuyu; compact, stays under 20ft", "flesh_fruit": "Cinnamon-orange flesh when ripe; sweet", "yield_notes": "Good yields", "growing_notes": "", "availability": "", "sort_order": 21}, {"name": "Sheng", "slug": "sheng", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "China, traditional variety", "traits": "Flat shape resembling heirloom tomato; lobed sections around calyx", "flesh_fruit": "Sweet with notes of clove and cinnamon; unique flavor profile", "yield_notes": "Good production", "growing_notes": "SUITABLE FOR BRISBANE - Chinese heirloom. Zones 6-9 so more cold-hardy but adapts to Brisbane. Unique spiced flavor.", "availability": "Specialty nurseries", "sort_order": 22}, {"name": "Rojo Brillante (Sharon Fruit)", "slug": "rojo-brillante-sharon-fruit", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Spain, developed for European markets", "traits": "Large, deep orange-red fruit; commercially important in Spain", "flesh_fruit": "Astringent but commercially treated with CO2 to remove astringency while still firm; very sweet; seedless", "yield_notes": "Excellent commercial yields", "growing_notes": "SUITABLE FOR BRISBANE - Heat tolerant. Major marketing success in Europe. Can be grown successfully in Brisbane.", "availability": "Daley''s Fruit, specialty nurseries", "sort_order": 23}, {"name": "Pomelo", "slug": "pomelo", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Selection", "traits": "Prolific bearer; large to extra-large fruit; deep orange", "flesh_fruit": "Very sweet when fully ripe; luscious jelly-like consistency", "yield_notes": "Prolific - very heavy bearer", "growing_notes": "SUITABLE FOR BRISBANE - Heat tolerant. Extremely productive for home gardens.", "availability": "Daley''s Fruit", "sort_order": 24}, {"name": "Triumph (Tropical Persimmon, Sharon Fruit) 🌱", "slug": "triumph-tropical-persimmon-sharon-fruit", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Developed for warm climates; grown in Florida, Israel; name varies by region", "traits": "Small 6-7cm diameter; oblate shape; tomato-like appearance; thin, smooth skin; highly productive", "flesh_fruit": "Astringent when firm, but can be CO2-treated; dark orange-red when ripe; very soft, jelly-like when ready; seedless", "yield_notes": "Heavy, reliable crops in tropical conditions", "growing_notes": "", "availability": "", "sort_order": 0}, {"name": "Fuyu", "slug": "fuyu", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Japan, late 1800s; name means ''winter''", "traits": "Round, squat fruit 5-7cm; bright orange; semi-dwarf to 15ft; heat-tolerant", "flesh_fruit": "Non-astringent; crisp and sweet when firm; seedless; excellent fresh eating", "yield_notes": "Heavy, consistent producer; self-pollinating", "growing_notes": "SUITABLE FOR KERALA - Native to subtropical climates, tolerates heat and humidity very well. Requires minimal chill (100-200 hours). Can adapt to tropical conditions with proper care. Most widely grown persimmon globally. Heat zones 7-11 indicates good heat tolerance. Handles monsoon humidity. Self-fertile.", "availability": "M-Tech Gardens India, ZXXYANBI India (grafted plants), Kerala nurseries, Amazon India", "sort_order": 1}, {"name": "Hachiya", "slug": "hachiya", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Japan, widely cultivated traditional variety", "traits": "Large acorn-shaped fruit; bright orange; vigorous tree", "flesh_fruit": "Astringent until soft; intensely sweet, honeyed; jelly-like; seedless", "yield_notes": "Productive; heavy bearer", "growing_notes": "SUITABLE FOR KERALA - Requires hot summers to ripen fruit fully - Kerala provides this. Best flavor and quality in warm climates. Heat zones 7-10. Self-fertile. Handles high heat well. May struggle with excessive monsoon moisture without proper drainage.", "availability": "Indian nurseries, Rudra Agro Nursery Pune, specialty tropical fruit suppliers", "sort_order": 2}, {"name": "Tanenashi", "slug": "tanenashi", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Japan, means ''seedless''", "traits": "Medium-large conical fruit; orange-red; vigorous tree", "flesh_fruit": "Yellow-orange; sweet, rich; completely seedless; dry texture", "yield_notes": "Heavy, prolific producer", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "Eureka", "slug": "eureka", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "USA selection", "traits": "Medium, flat fruit; red skin; compact tree; self-fruitful", "flesh_fruit": "Extremely high quality; contains seeds; stores well", "yield_notes": "Heavy producing; proven commercial variety", "growing_notes": "SUITABLE FOR KERALA - Popular across Asia. Heat zones 8-11 indicating excellent heat tolerance. Can adapt to tropical conditions. Self-fertile advantage.", "availability": "International nurseries, specialty Indian suppliers", "sort_order": 4}, {"name": "Jiro (Ichikikei Jiro)", "slug": "jiro-ichikikei-jiro", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Japan, traditional cultivar from 1800s", "traits": "Large, square fruit; flat with lobes; compact tree 12-15ft", "flesh_fruit": "Non-astringent; firm, crisp, sweet; seedless; thin tender skin", "yield_notes": "Excellent when mature; productive", "growing_notes": "SUITABLE FOR KERALA - Humidity tolerant. More cold-hardy than Fuyu but also heat-adaptable. Self-pollinating. Can handle tropical conditions with good drainage.", "availability": "Specialty nurseries in India, international suppliers", "sort_order": 5}, {"name": "Izu", "slug": "izu", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Japan, early variety", "traits": "Small to medium, tomato-shaped; bright orange; semi-dwarf", "flesh_fruit": "Non-astringent; sweet, crisp; pale orange flesh; seedless", "yield_notes": "Good cropping for tree size", "growing_notes": "SUITABLE FOR KERALA - Early ripening suits tropical climate. Heat tolerant. More cold-hardy than Fuyu, indicating climate adaptability. Compact size good for Kerala home gardens.", "availability": "Specialty Indian nurseries", "sort_order": 6}, {"name": "Suruga", "slug": "suruga", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Japan", "traits": "Medium-large fruit; reddish-orange skin", "flesh_fruit": "Very sweet - one of sweetest non-astringents; spicy-sweet; no astringency", "yield_notes": "Good production", "growing_notes": "SUITABLE FOR KERALA - Researched for subtropical Australia (Queensland) indicating good heat/humidity tolerance. Heat zones 7-11. Can adapt to tropical conditions.", "availability": "Specialty nurseries", "sort_order": 7}, {"name": "Ormond", "slug": "ormond", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Florida selection, traditional variety", "traits": "2.5in long, 2in diameter; reddish-yellow outside, deep orange-red inside; fruits hang in clusters like grapes; vigorous tree", "flesh_fruit": "Very sweet, moderately juicy; astringent until soft; large seeds", "yield_notes": "Good production; cluster fruiting", "growing_notes": "EXCELLENT FOR KERALA - SPECIFICALLY SUITED TO WARMER CLIMATES. Developed in Florida (similar tropical climate to Kerala). Breaks bud early in spring, increasing chances of fruit set in tropical areas. Mid-sized tree suited to Kerala conditions. Heat and humidity adapted.", "availability": "Florida nurseries, tropical fruit specialists", "sort_order": 8}, {"name": "Coffee Cake", "slug": "coffee-cake", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "USA selection", "traits": "Brownish flesh; firm when ripe; medium-sized fruit", "flesh_fruit": "Sweet, rich, spicy - named after flavor; non-astringent; unique taste", "yield_notes": "Good yields; needs pollinator (Chocolate variety best)", "growing_notes": "SUITABLE FOR KERALA - Heat zones 7-10. Ripens a month before Fuyu (fall/winter ripening). Warm climate adapted. Unique spiced flavor profile.", "availability": "Specialty nurseries, Four Winds Growers (USA)", "sort_order": 9}, {"name": "Chocolate (American Persimmon hybrid)", "slug": "chocolate-american-persimmon-hybrid", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "USA, American persimmon variety", "traits": "Small to medium oblong fruit; bright red skin; chocolate-colored flesh", "flesh_fruit": "Firm, dotted chocolate specks; sweet with cocoa hints; non-astringent (rare for American type)", "yield_notes": "Good production; self-fruitful (rare for American persimmons)", "growing_notes": "SUITABLE FOR KERALA - Heat zones 7-10. Heat tolerant. Self-fertile advantage. Unique chocolate flesh. Ripens late Oct-November.", "availability": "Four Winds Growers, specialty nurseries", "sort_order": 10}, {"name": "Diospyros kaki (Common Persimmon - Seedling Type) 🌱", "slug": "diospyros-kaki-common-persimmon-seedling-type", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Various regions - seedling selections; traditional types", "traits": "Variable traits; grown from seed; ornamental tree with orange autumn foliage", "flesh_fruit": "Quality varies; generally astringent; fruits in 5-7 years from seed", "yield_notes": "Variable depending on genetics", "growing_notes": "SUITABLE FOR KERALA - Seedling persimmons often more adaptable to varied climates. Used as rootstock. Can produce in tropical/subtropical conditions. Available in Kerala nurseries. More genetic diversity for climate adaptation. Good for Kerala experimentation.", "availability": "Kerala Garden, Zoropic Enterprise, M-Tech Gardens, local Kerala nurseries", "sort_order": 11}, {"name": "Japani Phal (Local Indian Name)", "slug": "japani-phal-local-indian-name", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Traditional name in India for persimmon; multiple varieties sold under this name", "traits": "Variable - general term for persimmons in North India (Himachal, J&K, Uttarakhand)", "flesh_fruit": "Deep orange-red color; tomato-like appearance; soft, sweet when fully ripe", "yield_notes": "Variable", "growing_notes": "INDIGENOUS NAME IN INDIA - Cultivated in Indian temperate regions (Himachal, J&K, Tamil Nadu, Uttarakhand) but some selections may adapt to Kerala with proper care. Look for heat-tolerant selections. Traditional Indian cultivation knowledge. Also known as Amarphal (Hindi).", "availability": "Indian nurseries nationwide, Rudra Agro Nursery Pune, regional nurseries", "sort_order": 12}, {"name": "Nikita''s Gift", "slug": "nikita-s-gift", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "origin": "Ukraine/Russia, hybrid: Rosseyanka (D. kaki x D. virginiana) x D. kaki", "traits": "2.5-3in fruit; flat bottom; dark reddish-orange; small to medium tree", "flesh_fruit": "Exceptionally sweet when ripe; astringent; loses astringency easier than many varieties", "yield_notes": "Good production", "growing_notes": "SUITABLE FOR KERALA - Very cold-hardy but ALSO heat-adaptable due to hybrid vigor. Ripens earlier than Saijo. Better for areas with long growing season but lacking extreme heat. Good for Kerala''s moderate heat with humidity.", "availability": "Stark Bros, specialty nurseries", "sort_order": 13}, {"name": "Rosseyanka", "slug": "rosseyanka", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "origin": "Ukraine, hybrid: D. kaki x D. virginiana", "traits": "Small to medium fruit; American persimmon flavor profile", "flesh_fruit": "Very sweet; resembles American persimmon; astringent until soft", "yield_notes": "Very productive", "growing_notes": "SUITABLE FOR KERALA - Very cold-hardy to -25°F but hybrid vigor gives climate adaptability. Can handle temperature extremes. Good for experimental Kerala cultivation.", "availability": "Specialty nurseries, Trees of Joy", "sort_order": 14}], "variety_count": 40}'::jsonb,
