UPDATE public.garden_import_queue SET payload = '{"species": "Pine", "species_slug": "pine", "varieties": [{"name": "Slash Pine (Pinus elliottii var. elliottii)", "slug": "slash-pine-pinus-elliottii-var-elliottii", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Southeastern United States (South Carolina to Louisiana), introduced to Queensland late 1920s", "traits": "Medium to large tree reaching 30-35m height, stem diameter 0.7m. Large spreading branches, gray to red-brown bark deeply fissured, needles 15-30cm long in groups of 2-3 (usually 2)", "flesh_fruit": "", "yield_notes": "Excellent productivity in subtropical conditions with 25-30 year rotation", "growing_notes": "", "availability": "Widely available from Queensland nurseries and HQPlantations. Major commercial plantation species in Brisbane region", "sort_order": 0}, {"name": "Caribbean Pine (Pinus caribaea var. hondurensis)", "slug": "caribbean-pine-pinus-caribaea-var-hondurensis", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Central America and Caribbean (Bahamas, Honduras, Nicaragua), introduced to Queensland 20th century", "traits": "Lowland tropical evergreen reaching 35+ meters. Aggressive growth even in harsh conditions. Needles in bundles of 3 (occasionally 2, 4, or 5), measuring 15-30cm long. Symmetrical cones 5-12cm on short stalks", "flesh_fruit": "", "yield_notes": "Rapid productivity with 25-30 year rotation in subtropical plantations", "growing_notes": "", "availability": "Queensland plantation forestry suppliers, HQPlantations commercial varieties", "sort_order": 1}, {"name": "Hybrid Southern Pine (P. elliottii × P. caribaea)", "slug": "hybrid-southern-pine-p-elliottii-p-caribaea", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Developed in Queensland through selective breeding programs, mid-20th century", "traits": "Combines best attributes of both parents - Slash pine''s straightness, high wood density, wet site tolerance with Caribbean pine''s fast growth, fine branching, even texture", "flesh_fruit": "", "yield_notes": "Outstanding productivity for subtropical Queensland conditions. Annual sustainable yield up to 1.8 million m³", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "Hoop Pine (Araucaria cunninghamii) 🌏", "slug": "hoop-pine-araucaria-cunninghamii", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Indigenous to Australia - northeastern New South Wales to Far North Queensland (0-1,000m elevation), also Papua New Guinea. Named after botanist Allan Cunningham who collected specimens in 1820s", "traits": "Majestic subtropical rainforest species reaching 60m height, 4m girth. Straight cylindrical trunk. Distinctive horizontal rings of scaly bark resembling hoops when stripped. Awl-shaped juvenile leaves (1-2cm), scale-like incurved mature leaves. Needle-like dark green leaves 2-4cm long", "flesh_fruit": "", "yield_notes": "20-30 year maturity. Can live 450+ years. Slow initial growth but rapid once established", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "Radiata Pine (Pinus radiata)", "slug": "radiata-pine-pinus-radiata", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "California Central Coast (Monterey region), introduced to Australia 1870s-1876", "traits": "Fast-growing medium-density softwood, 30-45m tall, 30-90cm diameter. Straight stems, narrow crowns, small branches. Deeply ridged dark brown bark aging gray. Needles 7.5-15cm long in groups of three. Large asymmetrical cones 7-17cm on curved stalks", "flesh_fruit": "", "yield_notes": "Very rapid - up to 2m growth per year. 30-35 year rotation. Mean annual increment 16-21 m³/ha/yr in most sites", "growing_notes": "", "availability": "Queensland plantation suppliers, specialty forestry nurseries. Less common in Brisbane area than in southern Australia", "sort_order": 4}, {"name": "Canary Island Pine (Pinus canariensis)", "slug": "canary-island-pine-pinus-canariensis", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Canary Islands (Gran Canaria, Tenerife, El Hierro, La Palma), first described 1825. Planted experimentally in Australia 1888-1895 and 1927-1931", "traits": "Large evergreen 30-40m tall (exceptionally 56m), 100-120cm diameter. Thick scaly bark patterned red-brown and buff. Long drooping needles 20-30cm in bundles of three, green to yellow-green. Glossy chestnut-brown serotinous cones 10-18cm long", "flesh_fruit": "", "yield_notes": "Moderate growth rate in subtropical conditions", "growing_notes": "", "availability": "Queensland botanical gardens, specialty conifer nurseries, ornamental tree suppliers", "sort_order": 5}, {"name": "Norfolk Island Pine (Araucaria heterophylla)", "slug": "norfolk-island-pine-araucaria-heterophylla", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "origin": "Endemic to Norfolk Island, discovered by Europeans 1768. Native to Australia/New Zealand region. Widely naturalized along Australian coastline", "traits": "Large tree 20-35m tall, 10-15m wide. Distinctive symmetrical pyramid shape, dark evergreen foliage. Soft needles (unlike other conifers). Can live 2,000 years", "flesh_fruit": "", "yield_notes": "Long-lived ornamental, not typically harvested for timber in cultivation", "growing_notes": "", "availability": "Widely available from Queensland coastal nurseries, garden centers throughout Brisbane region", "sort_order": 6}, {"name": "Maritime Pine (Pinus pinaster)", "slug": "maritime-pine-pinus-pinaster", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Western Mediterranean Sea region, introduced to Australia 19th century", "traits": "Fast-growing conifer to 35m, rapid annual growth until age 60. Long needles in pairs (greater than 15cm). Large slightly asymmetrical cones 9-20cm, almost stalkless", "flesh_fruit": "", "yield_notes": "Fast growth in subtropical conditions", "growing_notes": "", "availability": "", "sort_order": 7}, {"name": "Aleppo Pine (Pinus halepensis)", "slug": "aleppo-pine-pinus-halepensis", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Mediterranean region (Morocco to Greece), named after Aleppo, Syria. Introduced to Australia for ornamental/forestry use", "traits": "Small to medium tree 15-25m tall, trunk 60cm diameter (exceptionally 1m). Orange-red bark thick and fissured at base, thin and flaky in crown. Very slender yellowish-green needles 6-12cm long in pairs. Symmetrical cones 5-14cm on curved stalks", "flesh_fruit": "", "yield_notes": "Fast growth in hot, dry conditions", "growing_notes": "", "availability": "Queensland ornamental tree suppliers, public park specimens", "sort_order": 8}, {"name": "Stone Pine (Pinus pinea)", "slug": "stone-pine-pinus-pinea", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Mediterranean region, cultivated since 4th century BC. Introduced to Australia 1700s-1800s for ornamental use", "traits": "Distinctive umbrella-shaped crown at maturity. 12-20m typical height (can exceed 25m). Red-brown bark deeply furrowed. Needles in pairs, 10-18cm long. Oval/spherical cones 10cm long ripening over 3 years to glossy chestnut-brown", "flesh_fruit": "", "yield_notes": "Slow-growing, 7-12 years to start bearing. Takes 3 years from pollination to cone ripening", "growing_notes": "", "availability": "Ornamental nurseries, Italian cultural gardens, specialty Mediterranean plant suppliers", "sort_order": 9}, {"name": "Bunya Pine (Araucaria bidwillii) 🌏", "slug": "bunya-pine-araucaria-bidwillii", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Indigenous to southeastern Queensland highlands (Bunya Mountains region). World Heritage species. One of oldest tree species", "traits": "Large conifer native to highly humid southeastern Queensland. Reaches 45m height. Huge cones and edible seeds (considered delicious). Fine pointy needles. Self-sufficient within first two years", "flesh_fruit": "", "yield_notes": "Very long-lived, slow initial growth", "growing_notes": "", "availability": "Queensland native plant nurseries, Bunya Mountains National Park seed programs, protected species with cultivation restrictions", "sort_order": 10}, {"name": "Khasi Pine (Pinus kesiya) 🌏", "slug": "khasi-pine-pinus-kesiya", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Indigenous to India (Khasi Hills, Meghalaya - northernmost limit of range), also Thailand, Myanmar, Laos, China, Vietnam, Philippines. Named after Khasi Hills. Known as Thông ba lá (Vietnamese), 思茅松 (Chinese), son-songbai (Thai)", "traits": "One of most widely distributed Asian pines. Subtropical to temperate tree reaching 30-35m height. Straight cylindrical trunk, thick dark brown bark with deep longitudinal fissures. Dark green needles usually 3 per fascicle, 15-20cm long. Robust red-brown branches horizontal to drooping", "flesh_fruit": "", "yield_notes": "Slow-growing first 5 years, then becomes fairly fast. Important plantation species throughout Asia, Africa, South America", "growing_notes": "", "availability": "Indian forestry departments, northeastern India plantations, Kerala Forest Research Institute, traditional seed sources from Meghalaya and Assam regions", "sort_order": 0}, {"name": "Chir Pine (Pinus roxburghii) 🌏", "slug": "chir-pine-pinus-roxburghii", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Indigenous to Himalayas - Tibet, Afghanistan, Pakistan, northern India (Jammu & Kashmir, Himachal Pradesh, Uttarakhand, Sikkim, Arunachal Pradesh), Nepal, Bhutan, Myanmar. Named after botanist William Roxburgh. Also called Longleaf Indian Pine", "traits": "Large tree 30-50m tall, trunk diameter up to 2-3m. Red-brown bark thick and deeply fissured at base, thinner and flaky in upper crown. Very slender yellowish-green needles in fascicles of three, 20-35cm long. Cones 12-24cm long, green ripening to glossy chestnut-brown over 24 months", "flesh_fruit": "", "yield_notes": "16% of Uttarakhand forests covered by Chir pine. Over 15 lakh tonnes pine needles generated annually in Uttarakhand alone", "growing_notes": "", "availability": "Himalayan state forestry departments, highland Kerala experimental forestry stations, Idukki district plantation programs", "sort_order": 1}, {"name": "Merkus Pine (Pinus merkusii) 🌏", "slug": "merkus-pine-pinus-merkusii", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Indigenous to India (Northeast Frontier - Assam, Meghalaya regions), Myanmar, Thailand, Laos, Vietnam, Philippines, Indonesia (Sumatra). Only pine species with natural distribution extending south of equator (northern Sumatra 1-2°S). Also called Sumatran Pine, Mindoro Pine, Cambodian Pine", "traits": "Truly tropical pine, large tree 25-45m tall (exceptionally 50-70m), trunk up to 140cm diameter. Orange-red bark thick and deeply fissured at base, thin and flaky in upper crown. Very slender needles in pairs, 15-25cm long, green to yellowish-green. Cylindrical cones 5-11cm long", "flesh_fruit": "", "yield_notes": "First thinning 9-10 years, subsequent thinning every 5 years. 30-year rotation for optimal timber. 15-year rotation for pulpwood. Viable seeds produced year-round in Sumatra, most abundantly July-November", "growing_notes": "", "availability": "Northeast India forestry departments, experimental tropical pine plantations, Kerala Forest Research Institute for tropical species trials", "sort_order": 2}, {"name": "Blue Pine (Pinus wallichiana) 🌏", "slug": "blue-pine-pinus-wallichiana", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Indigenous to Himalayas - Afghanistan, Pakistan, northern India, Nepal, Bhutan, Tibet, Myanmar. Also called Himalayan White Pine, Bhutan Pine", "traits": "Large Himalayan pine reaching 30-50m height. Distinctive bluish-green soft needles in bundles of 5, 12-18cm long. Drooping slender needles give graceful appearance. Long pendant cones 15-32cm", "flesh_fruit": "", "yield_notes": "Moderate growth in montane conditions", "growing_notes": "", "availability": "Himalayan state forestry programs, high-elevation experimental stations in Kerala Western Ghats, Munnar/Idukki district specialty nurseries", "sort_order": 3}, {"name": "Casuarina (Australian Pine/She Oak - Casuarina equisetifolia)", "slug": "casuarina-australian-pine-she-oak-casuarina-equisetifolia", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Northern Australia, Southeast Asia, Pacific Islands. Introduced throughout tropics", "traits": "Fast-growing evergreen to 8-16m (up to 30m in Southeast Asia). Thin drooping branches resembling horsetail (hence ''equisetifolia'' meaning horsehair). Not a true pine but needle-like branchlets give pine-like appearance", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "Widely available throughout Kerala nurseries, coastal plantation programs, agroforestry suppliers", "sort_order": 4}], "variety_count": 16}'::jsonb,
  variety_count = 16, status = 'parsed'
WHERE source_path = 'brainstorm-inbox/import-payloads/pine.json';

