UPDATE public.garden_import_queue SET payload = '{"species": "Plum", "species_slug": "plum", "varieties": [{"name": "Gulf Gold", "slug": "gulf-gold", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Florida, USA breeding program, 1980s", "traits": "Medium to large size, yellow skin with red blush, attractive appearance", "flesh_fruit": "Firm golden-yellow flesh, juicy, excellent sweet flavor, clingstone, small seed", "yield_notes": "Very productive, bears heavily even in warm climates", "growing_notes": "Very low chill requirement (275 hours), specifically bred for subtropical and coastal regions. Resistant to bacterial spot. Self-pollinating but benefits from Gulf Ruby. Perfect for Brisbane''s climate, frost-free sites. First plums ready October. Grows well in half wine barrels.", "availability": "Daleys Nursery, Fruit Salad Trees, widely available in Queensland", "sort_order": 0}, {"name": "Gulf Ruby", "slug": "gulf-ruby", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Florida, USA breeding program, 1980s", "traits": "Deep red skin, medium to large size, clingstone", "flesh_fruit": "Firm yellow flesh, delicious eaten fresh, sweet and juicy", "yield_notes": "Heavy cropper, excellent productivity", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "Gulf Blaze", "slug": "gulf-blaze", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Florida breeding program, 1980s", "traits": "Red skin, medium size, early flowering and early ripening", "flesh_fruit": "Firm yellow flesh, sweet, good texture", "yield_notes": "Reliable cropper in warm climates", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "Santa Rosa", "slug": "santa-rosa", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "California, USA by Luther Burbank, 1906", "traits": "Large, purplish-crimson to deep crimson skin with pale blue bloom, freestone", "flesh_fruit": "Yellow flesh with red blush near skin, mildly sweet with some tartness near skin and stone, juicy", "yield_notes": "Good bearer, considered one of the best plums", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "Mariposa", "slug": "mariposa", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "California, USA, early 1900s", "traits": "Large heart-shaped fruit, dark red to maroon skin with green-khaki lenticels giving spotted effect", "flesh_fruit": "Blood red flesh, fine textured, juicy, soft when ripe, sweet flavor with good acid balance", "yield_notes": "Excellent bearer, crops well in most Australian regions", "growing_notes": "Low chill variety, the ''old blood plum everyone remembers''. Partially self-fertile but benefits from Santa Rosa pollination. Popular for jams and sauces. Suitable for early to mid-season harvest (late January). Regular thinning ensures larger fruit size. Widely recognized heritage variety for subtropical regions.", "availability": "Widely available - PlantNet, Yalca, Engalls, Fruit Salad Trees, Fruitopia Nursery Brisbane", "sort_order": 4}, {"name": "Satsuma", "slug": "satsuma", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "China, introduced to USA in 19th century", "traits": "Medium to large rounded fruit, red to dark red skin, freestone", "flesh_fruit": "Deep red to purple flesh, tender, sweet and juicy with satisfying clove-like depth of flavor", "yield_notes": "Good bearer, vigorous growth, may require fruit thinning", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "Dorrigo Blood", "slug": "dorrigo-blood", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australian selection, Daleys Nursery unique variety", "traits": "Large fruit, pale skin with reddish tones", "flesh_fruit": "Deep blood red flesh, sensational flavor, smooth soft texture, very juicy, sweet right to seed, sweet mild skin", "yield_notes": "Good productivity, one of largest blood plums", "growing_notes": "Low chill blood plum (300-400 hours), self-pollinating. Superb for cooler climates but will crop in subtropics. Cross-pollinate with Satsuma for best results. Unique to Daleys Nursery. Suitable for Brisbane conditions. Ripens late January-early February.", "availability": "Daleys Nursery (exclusive)", "sort_order": 6}, {"name": "Amber Jewel", "slug": "amber-jewel", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australian variety, developed in Australia", "traits": "Large fruit (63-70mm), red skin with yellow background, excellent shelf life", "flesh_fruit": "Amber flesh, super sweet, meaty crisp texture, unique flavor", "yield_notes": "Medium vigorous tree, large fruit production, high quality", "growing_notes": "Matures one month after Santa Rosa. Great storage capability. Partially self-fertile, Santa Rosa is compatible pollinator. Will make people come back for more due to exceptional sweetness. Ripens early February. Suitable for Brisbane subtropical climate.", "availability": "Daleys Nursery, Australian nurseries", "sort_order": 7}, {"name": "Sunrise Gulf", "slug": "sunrise-gulf", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Florida breeding program", "traits": "Large purple fruits, medium to large red clingstone", "flesh_fruit": "Pale green/yellow flesh, sweet and juicy", "yield_notes": "Great quality fruits in warmer areas", "growing_notes": "", "availability": "", "sort_order": 8}, {"name": "A-Okay™", "slug": "a-okay", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Modern breeding program", "traits": "Modern low chill variety", "flesh_fruit": "Good quality, suitable for fresh eating", "yield_notes": "Reliable cropper in warm climates", "growing_notes": "", "availability": "", "sort_order": 9}, {"name": "Yarrahapinni Blood", "slug": "yarrahapinni-blood", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australian selection, warm climate variety", "traits": "Small to medium size, deep red foliage, striking pink blossoms in spring", "flesh_fruit": "Dark colored flesh, juicy and sweet", "yield_notes": "Good productivity in warm climates", "growing_notes": "", "availability": "", "sort_order": 10}, {"name": "Kyogle Early", "slug": "kyogle-early", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australian selection, under trial at Daleys Nursery", "traits": "Red skin, compact habit tree, early flowering", "flesh_fruit": "Gorgeous amber flesh, early ripening", "yield_notes": "Shows promise, compact growth habit", "growing_notes": "Low chill plum under trial. First plums of season ready in October in Kyogle (northern NSW). Very early ripening. Compact tree habit ideal for smaller spaces. Being evaluated for subtropical performance.", "availability": "Daleys Nursery (trial variety)", "sort_order": 11}, {"name": "Black Adder Pluot", "slug": "black-adder-pluot", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Graham Richards low chill breeding program, Australia", "traits": "Plum-apricot hybrid (Pluot), purplish-black skin", "flesh_fruit": "Amber flesh turning deeper when very ripe, excellent flavor and texture", "yield_notes": "Good productivity, first fruiting shows promise", "growing_notes": "Low chill variety specifically bred for Australian subtropical conditions. Cross between apricot and plum with more plum characteristics. Requires cross-pollination with another Pluot or Japanese plum variety like Mariposa. Australian breeding innovation.", "availability": "Daleys Nursery (exclusive Graham Richards variety)", "sort_order": 12}, {"name": "Flavour Supreme Pluot", "slug": "flavour-supreme-pluot", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "California, USA, interspecific breeding", "traits": "Plum-apricot hybrid, medium size", "flesh_fruit": "Bright flavor, very sweet, excellent taste", "yield_notes": "Productive, prolific cropper", "growing_notes": "One of new generation of traditionally bred plums. Fruits early to mid-summer. Red to deep plum colored skin with mulberry red flesh. Suitable for cool temperate to warm areas. Suggested pollinator Mariposa. May adapt to Brisbane with proper care.", "availability": "Daleys, Flower Power, specialty nurseries", "sort_order": 13}, {"name": "Donsworth", "slug": "donsworth", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Japanese blood plum, heritage variety", "traits": "Dark maroon with red/green spots, large freestone, egg-shaped fruit", "flesh_fruit": "Dark red flesh, tart skin but sweet flesh, excellent flavor", "yield_notes": "Good producer, large fruit if thinned", "growing_notes": "Old-fashioned blood plum. Stores and handles well - Taiwan market favorite after 16 days sea freight. Harvested mid-January. Pollinates with Narrabeen and Mariposa. Wide climate range adaptability including Brisbane.", "availability": "PlantNet Australia, Australian commercial growers", "sort_order": 14}, {"name": "Queen Rosa", "slug": "queen-rosa", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australian commercial variety", "traits": "Nice red color, good size, old-fashioned plum smell", "flesh_fruit": "Yellow flesh, sweet with slight tart skin", "yield_notes": "Good productivity, reliable cropper", "growing_notes": "Harvested early January. Classic plum characteristics with nostalgic appeal. Pollinates with Satsuma. Suitable for Brisbane subtropical climate.", "availability": "Australian commercial fruit suppliers, Yalca", "sort_order": 15}, {"name": "Rose Zee", "slug": "rose-zee", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Early season Australian variety", "traits": "Red color, smallish fruit compared to others but early", "flesh_fruit": "Sweet yellow flesh", "yield_notes": "Good for early season production", "growing_notes": "", "availability": "", "sort_order": 16}, {"name": "Black Amber", "slug": "black-amber", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australian commercial variety", "traits": "Black plum with good size, excellent keeping ability", "flesh_fruit": "Amber flesh, sweet", "yield_notes": "Good productivity", "growing_notes": "", "availability": "", "sort_order": 17}, {"name": "Frontier", "slug": "frontier", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australian blood plum variety", "traits": "Heart shape, red skin, no tartness in skin", "flesh_fruit": "Lighter red flesh, sweet to eat", "yield_notes": "Good cropper", "growing_notes": "Blood plum harvested mid-January. Sweet skin without tartness makes it popular for fresh eating. Suitable for Brisbane conditions.", "availability": "Australian commercial growers", "sort_order": 18}, {"name": "Ruby Blood", "slug": "ruby-blood", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australian variety", "traits": "Medium to large freestone, red fruits", "flesh_fruit": "Blood red flesh, sweet and juicy", "yield_notes": "Great cropper, very popular late bearing variety", "growing_notes": "Medium-lower chill but not suitable to subtropical climates north of Brisbane. Pollinates with Spring Satin Plumcot, Narrabeen, Satsuma, Santa Rosa. Popular in Australia. Harvest January-February.", "availability": "PlantNet Australia (not recommended north of Brisbane)", "sort_order": 19}, {"name": "Narrabeen", "slug": "narrabeen", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australian variety", "traits": "Large pink/red clingstone fruits", "flesh_fruit": "Light red flesh, good quality", "yield_notes": "Good productivity", "growing_notes": "", "availability": "", "sort_order": 20}, {"name": "Elephant Heart", "slug": "elephant-heart", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "California, USA, early 20th century", "traits": "Large heart-shaped plum, dark red skin", "flesh_fruit": "Light red flesh, excellent flavor", "yield_notes": "Good productivity", "growing_notes": "", "availability": "", "sort_order": 21}, {"name": "Indian Coffee Plum (Flacourtia jangomas) 🌏", "slug": "indian-coffee-plum-flacourtia-jangomas", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Native to India and Southeast Asia, indigenous to Kerala", "traits": "Small deciduous tree 6-10m, thorns on young branches, light brown to copper-red flaky bark", "flesh_fruit": "Round berries 25mm diameter, soft flesh with 4-6 flattened seeds, sour tangy flavor, sweet when fully ripe", "yield_notes": "Abundant fruit every year in warm tropical climate", "growing_notes": "Perfect for Kerala''s warm tropical climate. Known locally as ''Lubikka'' in Malayalam. Eaten raw with salt to offset sourness. Used for jams, jellies, juices, preserves, pickles. Famous Lubikka pickles from Kerala exported worldwide. Traditional Ayurvedic medicinal uses. Flowers fragrant, smell like honey. Male and female flowers on separate trees.", "availability": "Local Kerala nurseries, Green Cover Initiative, indigenous to region", "sort_order": 0}, {"name": "Jamun / Java Plum (Syzygium cumini) 🌏", "slug": "jamun-java-plum-syzygium-cumini", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Native to India, indigenous across Indian subcontinent including Kerala", "traits": "Large evergreen tree 30-35ft (up to 100ft in native habitat), leathery glossy dark green leaves, dense canopy", "flesh_fruit": "Oblong purple-black fruit size of large olive, sweet-sour flavor, refreshing, stains tongue purple, fleshy pulp with pale oblong seed", "yield_notes": "Very high - mature trees produce 85-150 lbs fruit. Bears continuously 60-70 years", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "Governor''s Plum (Flacourtia indica) 🌏", "slug": "governor-s-plum-flacourtia-indica", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Native to tropical Africa and South Asia, traditional in Kerala/Karnataka", "traits": "Deciduous shrub or small tree 3-6m tall, thorny branches, ovate serrated leaves, glossy surface", "flesh_fruit": "Globose drupes ripen green to bright red-orange, tart fruit", "yield_notes": "Reliable cropper in dry tropics", "growing_notes": "Adapts to dry tropical regions with well-drained, slightly acidic soils. Prime cultivation zones include Karnataka and Tamil Nadu in India. Traditional Ayurvedic uses. Known as Batokia, Govardhanphalika. Used as digestive aid. Bark harvested pre-monsoon (March-May). Contains tannins, gallic acid, quercetin. Referenced in Kerala 16th century texts, British India archives.", "availability": "Kerala traditional medicine suppliers, specialized Ayurvedic nurseries", "sort_order": 2}, {"name": "Rainforest Plum (Eugenia candolleana)", "slug": "rainforest-plum-eugenia-candolleana", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Native to Atlantic rainforest of Brazil, adapted to Kerala", "traits": "Medium-sized shrubby tree 3-6m tall, rounded/conical canopy 2m wide, reddish brown peeling bark", "flesh_fruit": "Round or slightly elongated berry 20mm wide x 25mm long, purple-black skin, whitish pulp 3-5mm thick, edible, moderately sweet, jaboticaba-like aroma", "yield_notes": "Flowers in large clusters, fruits ripen several weeks later, purple and red fruited forms", "growing_notes": "Known locally as Cambuí roxo or Murtinha in Portuguese. Adapted to Kerala''s tropical conditions. Leaves rusty-brown initially turning yellow then deep dark green. Rare in wild, used in landscaping for bright green foliage and purple-black fruits. Suitable for Kerala''s humid climate.", "availability": "Greens of Kerala, specialty tropical fruit nurseries", "sort_order": 3}, {"name": "Kala Amritsari", "slug": "kala-amritsari", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Amritsar, Punjab, India - famous traditional variety", "traits": "Distinctively large size, darker skin compared to other Indian varieties", "flesh_fruit": "Yellowish flesh, extremely sweet flavor, juicy pulp", "yield_notes": "Highly productive, profuse flowering, high fruit set", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Satluj Purple", "slug": "satluj-purple", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Punjab, India - named after Sutlej River", "traits": "Dark purple skin with distinctive purplish-blue color, recognizable from distance", "flesh_fruit": "Very juicy and sweet, excellent for fresh juices and smoothies", "yield_notes": "Good productivity when cross-pollinated", "growing_notes": "Needs Kala Amritsari for cross-pollination. Low chill requirement suitable for warmer Indian climates. Grown in Punjab where Sutlej is primary river. Famous for juice production. May require adaptation trials in Kerala conditions.", "availability": "Punjab nurseries, northern India suppliers", "sort_order": 5}, {"name": "Alucha", "slug": "alucha", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Not native to India but pervasively grown in Himachal Pradesh", "traits": "Bright red, sometimes maroonish hues, medium size", "flesh_fruit": "Flavors between sweet and sour, contrasting taste", "yield_notes": "High cultivation, abundantly available", "growing_notes": "Name means ''juicy edible fruit'' in Hindi. Generally used for chutneys and pickles due to contrasting flavors. Most abundantly available plum in India. Grown in hilly regions. Not suitable for Kerala''s lowland tropical conditions.", "availability": "Himachal Pradesh nurseries, northern hill regions", "sort_order": 6}, {"name": "Golden Japan", "slug": "golden-japan", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Japan, cultivated in India - Himachal Pradesh and Uttarakhand", "traits": "Golden yellow color, medium-sized, sometimes small yellow dots on surface", "flesh_fruit": "Very sweet but not overly sweet, balanced flavor", "yield_notes": "Harvested in July (peak monsoon)", "growing_notes": "", "availability": "", "sort_order": 7}, {"name": "Santa Rosa (India)", "slug": "santa-rosa-india", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "California USA, 1906, cultivated in India - J&K, Himachal Pradesh", "traits": "Purple with red blush, vibrant appearance", "flesh_fruit": "Very tender and juicy flesh, sweet with undertone of tartness", "yield_notes": "Good productivity in suitable climates", "growing_notes": "", "availability": "", "sort_order": 8}, {"name": "Greengage (India cultivation)", "slug": "greengage-india-cultivation", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Iran origin, cultivated in Tamil Nadu for Indian market", "traits": "Greenish round fruit, not common green color for plums", "flesh_fruit": "Flavors similar to ripe mango, dried apricot, citrusy notes, versatile", "yield_notes": "Good for confectionery purposes", "growing_notes": "Best for confectionery due to versatile flavors. Cultivation in Tamil Nadu. Transported from Tamil Nadu to rest of country. High chill requirement limits Kerala suitability, but Tamil Nadu proximity suggests possible adaptation in Kerala highlands.", "availability": "Tamil Nadu nurseries, possibly Kerala highland regions", "sort_order": 9}, {"name": "Titron", "slug": "titron", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Indian selection of Japanese origin (Prunus salicina)", "traits": "Low chill requirement variety", "flesh_fruit": "Good taste, best consumed fresh", "yield_notes": "Suitable for Indian conditions", "growing_notes": "", "availability": "", "sort_order": 10}, {"name": "Kataru Chak", "slug": "kataru-chak", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Indian selection (Prunus salicina group)", "traits": "Low chill requirement variety", "flesh_fruit": "Suitable for fresh consumption", "yield_notes": "Adapted to Indian growing conditions", "growing_notes": "", "availability": "", "sort_order": 11}, {"name": "Indian Hog Plum / Ambarella (Spondias dulcis) 🌏", "slug": "indian-hog-plum-ambarella-spondias-dulcis", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Native to regions around Indian Ocean, tropical Asia", "traits": "Green when unripe, yellow when ripe, oval shaped, large hairy pit", "flesh_fruit": "Unripe: tangy, very crunchy/hard. Ripe: soft flesh, sweet with acidity, like mix of green mango and pineapple", "yield_notes": "Harvested mainly during summer", "growing_notes": "Known as June plum. Popular in South India including Kerala. Eaten raw with salt and chili powder or made into pickles and chutneys. Thrives in tropical conditions. Well-adapted to Kerala climate. Listed among main fruits grown in Kerala.", "availability": "Kerala nurseries, backyards, widely cultivated in state", "sort_order": 12}, {"name": "Methley", "slug": "methley", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "origin": "South Africa, 1920s-1930s", "traits": "Japanese type, low chill variety", "flesh_fruit": "Sweet, good quality", "yield_notes": "Self-fertile, reliable cropper", "growing_notes": "", "availability": "", "sort_order": 13}, {"name": "Wade", "slug": "wade", "lineage_type": "hybrid", "climate_slug": "tropical-monsoon", "origin": "Low chill breeding program", "traits": "Japanese type, low chill requirement", "flesh_fruit": "Good eating quality", "yield_notes": "Suitable for warm climates", "growing_notes": "", "availability": "", "sort_order": 14}, {"name": "Shiro", "slug": "shiro", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Japan, traditional variety", "traits": "Yellow-skinned plum, tender to cold", "flesh_fruit": "Sweet yellow flesh, both sweet and tangy", "yield_notes": "Good for fresh eating or baking", "growing_notes": "", "availability": "", "sort_order": 15}, {"name": "Kelsey", "slug": "kelsey", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "California, USA, 1870s", "traits": "Green plum turning yellow, shows marks easily being green", "flesh_fruit": "Lime green flesh going to yellow with odd red blush, very sweet with no acid, can grow quite large", "yield_notes": "Large fruit possible, popular at growers markets", "growing_notes": "", "availability": "", "sort_order": 16}], "variety_count": 39}'::jsonb,
