UPDATE public.garden_import_queue SET payload = '{"species": "Pumpkin", "species_slug": "pumpkin", "varieties": [{"name": "Queensland Blue", "slug": "queensland-blue", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Queensland, Australia (pre-1932, exact date unknown)", "traits": "Medium to large fruit (2-5kg), dark grey-blue ribbed skin, thin skin, classic Australian variety", "flesh_fruit": "Thick, deep orange, dry, stringless, sweet flavor", "yield_notes": "High yielding, 9kg per plant average", "growing_notes": "Ideal for subtropical climate. Can be grown year-round in Brisbane and tropical regions. Excellent humidity tolerance. Handles warm, moist conditions exceptionally well. One of Australia''s most iconic pumpkins.", "availability": "The Seed Collection, Diggers Club, Succeed Heirlooms, widely available throughout Queensland nurseries", "sort_order": 0}, {"name": "Jarrahdale", "slug": "jarrahdale", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Jarrahdale, Western Australia (cross between Blue Hubbard and Cinderella, introduced to US 1932)", "traits": "Medium-large (5-8kg), blue-grey-green skin with prominent ribbing, flattened shape", "flesh_fruit": "Golden-orange, thick, sweet, mildly flavored, firm and non-stringy", "yield_notes": "3-5 fruits per plant average", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "Kent (Jap Pumpkin)", "slug": "kent-jap-pumpkin", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Japan (traditional variety)", "traits": "Medium (4-5kg), dark green skin mottled with yellow-brown patches, round shape", "flesh_fruit": "Light orange, firm, excellent nutty flavor, sweet", "yield_notes": "Good productivity", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "Butternut Waltham", "slug": "butternut-waltham", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Waltham, Massachusetts, USA (developed 1940s by Charles Leggett)", "traits": "Small to medium (1.5-2.5kg), pear-shaped, pale tan/beige skin, elongated neck", "flesh_fruit": "Deep orange, smooth texture, sweet and nutty (smooth as butter, sweet as a nut)", "yield_notes": "High yield, 6kg per plant, 4-5 fruits per vine", "growing_notes": "Grows well in Brisbane''s subtropical climate. Small seed cavity. Intermediate powdery mildew resistance. Stores extremely well (up to 6 months). One of the world''s most popular culinary pumpkins.", "availability": "The Seed Collection, Diggers Club, Eden Seeds, widely available", "sort_order": 3}, {"name": "Ironbark", "slug": "ironbark", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Victoria, Australia (gold mining era 1950s)", "traits": "Large, dark green skin, thick tough slightly bumpy skin", "flesh_fruit": "Rich orange, sweet, dense, dry-fleshed", "yield_notes": "Good producer", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Australian Butter", "slug": "australian-butter", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Melbourne, Victoria, Australia (Diggers Gardens Club)", "traits": "Large (up to 6kg), pale orange-yellow skin", "flesh_fruit": "Thick, dry, orange, small seed cavity", "yield_notes": "High yielding", "growing_notes": "Excellent for baking and roasting. Outstanding storage qualities. Well-suited to Brisbane''s climate. Rare Australian heirloom.", "availability": "Diggers Club (members), specialty Australian seed savers", "sort_order": 5}, {"name": "Triamble", "slug": "triamble", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Australia (dates to at least 1930s)", "traits": "Large (3-5kg), unique three-lobed shape, thick blue-grey skin, distinctive shamrock appearance", "flesh_fruit": "Yellow to deep orange, dry, sweet, rich tasting", "yield_notes": "Dense and heavy fruits", "growing_notes": "", "availability": "", "sort_order": 6}, {"name":